import{_ as a,o as i,c as o,a2 as r}from"./chunks/framework.DCVnL8g5.js";const m=JSON.parse('{"title":"Apache NiFi","description":"","frontmatter":{},"headers":[],"relativePath":"data-engineering/nifi/01-introduccion.md","filePath":"data-engineering/nifi/01-introduccion.md","lastUpdated":1782521464000}'),l={name:"data-engineering/nifi/01-introduccion.md"};function s(n,e,t,c,d,u){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="apache-nifi" tabindex="-1">Apache NiFi <a class="header-anchor" href="#apache-nifi" aria-label="Permalink to &quot;Apache NiFi&quot;">​</a></h1><p>Apache NiFi es una plataforma de flujo de datos orientada a ingesta, routing, transformaciones ligeras y movimiento fiable entre sistemas. Su punto fuerte es que permite disenar flujos de forma visual, observar que ocurre con cada FlowFile y cambiar rutas operativas sin convertir todo en codigo.</p><p>NiFi encaja muy bien cuando necesitas conectar sistemas, mover ficheros, enrutar eventos, enriquecer metadatos, llamar APIs, escribir en colas o bases de datos y dejar trazabilidad de lo que ha ocurrido.</p><h2 id="capitulos" tabindex="-1">Capitulos <a class="header-anchor" href="#capitulos" aria-label="Permalink to &quot;Capitulos&quot;">​</a></h2><ol><li><a href="./01-introduccion">Introduccion</a></li><li><a href="./02-diseno-y-desarrollo-de-flujos">Diseno y desarrollo de flujos</a></li><li><a href="./03-optimizacion-y-administracion">Optimizacion y administracion</a></li><li><a href="./04-procesadores-controller-services-y-parametros">Procesadores, controller services y parametros</a></li><li><a href="./05-colas-back-pressure-y-errores">Colas, back pressure y errores</a></li><li><a href="./06-registry-despliegue-y-observabilidad">Registry, despliegue y observabilidad</a></li></ol><h2 id="cuando-usar-nifi" tabindex="-1">Cuando usar NiFi <a class="header-anchor" href="#cuando-usar-nifi" aria-label="Permalink to &quot;Cuando usar NiFi&quot;">​</a></h2><p>NiFi es buena eleccion para:</p><ul><li>Ingesta desde ficheros, APIs, SFTP, HTTP, bases de datos o colas.</li><li>Routing visual segun atributos o contenido.</li><li>Flujos operativos donde importa ver colas, errores y trazabilidad.</li><li>Integracion entre sistemas con protocolos distintos.</li><li>Enriquecimiento ligero antes de enviar datos a Kafka, un lake o un warehouse.</li><li>Procesos donde un equipo de datos necesita operar sin desplegar codigo para cada cambio menor.</li></ul><h2 id="cuando-no-usar-nifi" tabindex="-1">Cuando no usar NiFi <a class="header-anchor" href="#cuando-no-usar-nifi" aria-label="Permalink to &quot;Cuando no usar NiFi&quot;">​</a></h2><p>NiFi no deberia ser la herramienta principal para todo:</p><ul><li>Transformaciones analiticas pesadas: suele encajar mejor Spark, SQL, dbt o un motor distribuido.</li><li>Streaming con estado complejo: Kafka Streams, Flink o Spark Structured Streaming suelen ser mejores.</li><li>Logica de negocio grande y versionada como aplicacion: un servicio propio puede ser mas mantenible.</li><li>Modelado de datos en warehouse: dbt o SQL gestionado suelen ser mas adecuados.</li></ul><h2 id="componentes-principales" tabindex="-1">Componentes principales <a class="header-anchor" href="#componentes-principales" aria-label="Permalink to &quot;Componentes principales&quot;">​</a></h2><h3 id="flowfile" tabindex="-1">FlowFile <a class="header-anchor" href="#flowfile" aria-label="Permalink to &quot;FlowFile&quot;">​</a></h3><p>Un FlowFile es la unidad que se mueve por NiFi. Tiene dos partes:</p><ul><li><strong>Contenido:</strong> bytes reales del dato.</li><li><strong>Atributos:</strong> metadatos como nombre de fichero, ruta, MIME type, ids, timestamps o campos calculados.</li></ul><p>NiFi intenta evitar copiar contenido innecesariamente. Muchas operaciones modifican atributos o referencias internas.</p><h3 id="processor" tabindex="-1">Processor <a class="header-anchor" href="#processor" aria-label="Permalink to &quot;Processor&quot;">​</a></h3><p>Un processor ejecuta una accion concreta:</p><ul><li>Leer ficheros.</li><li>Consumir mensajes.</li><li>Invocar una API.</li><li>Evaluar condiciones.</li><li>Modificar atributos.</li><li>Convertir formatos.</li><li>Escribir en otro sistema.</li></ul><p>Ejemplos:</p><ul><li><code>GetFile</code></li><li><code>PutFile</code></li><li><code>InvokeHTTP</code></li><li><code>RouteOnAttribute</code></li><li><code>UpdateAttribute</code></li><li><code>QueryDatabaseTableRecord</code></li><li><code>PublishKafkaRecord_2_6</code></li></ul><h3 id="connection" tabindex="-1">Connection <a class="header-anchor" href="#connection" aria-label="Permalink to &quot;Connection&quot;">​</a></h3><p>Una connection une dos componentes y funciona como cola. Permite configurar:</p><ul><li>Relaciones que acepta.</li><li>Back pressure por cantidad de FlowFiles.</li><li>Back pressure por tamano total.</li><li>Priorizadores.</li><li>Expiracion de datos.</li></ul><h3 id="process-group" tabindex="-1">Process Group <a class="header-anchor" href="#process-group" aria-label="Permalink to &quot;Process Group&quot;">​</a></h3><p>Un process group agrupa una parte del flujo. Sirve para dividir responsabilidades:</p><ul><li>Ingesta.</li><li>Validacion.</li><li>Enrutado.</li><li>Publicacion.</li><li>Errores.</li></ul><p>Un buen flujo de NiFi se entiende por grupos bien nombrados, no por cientos de procesadores en el mismo canvas.</p><h3 id="controller-service" tabindex="-1">Controller Service <a class="header-anchor" href="#controller-service" aria-label="Permalink to &quot;Controller Service&quot;">​</a></h3><p>Un controller service define recursos compartidos:</p><ul><li>Conexiones a bases de datos.</li><li>Lectores y escritores de registros.</li><li>Clientes SSL.</li><li>Servicios de cache.</li><li>Esquemas.</li></ul><p>Permite reutilizar configuracion y evitar duplicacion.</p><h3 id="parameter-context" tabindex="-1">Parameter Context <a class="header-anchor" href="#parameter-context" aria-label="Permalink to &quot;Parameter Context&quot;">​</a></h3><p>Un parameter context guarda valores configurables por entorno:</p><ul><li>Hosts.</li><li>Rutas.</li><li>Topics.</li><li>Nombres de tablas.</li><li>Umbrales.</li><li>Credenciales sensibles.</li></ul><p>Es la forma moderna de separar configuracion de diseno del flujo.</p><h2 id="flujo-minimo" tabindex="-1">Flujo minimo <a class="header-anchor" href="#flujo-minimo" aria-label="Permalink to &quot;Flujo minimo&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GetFile -&gt; UpdateAttribute -&gt; LogAttribute -&gt; PutFile</span></span></code></pre></div><p>Este flujo:</p><ol><li>Lee archivos de una carpeta.</li><li>Anade metadatos.</li><li>Registra atributos para depuracion.</li><li>Escribe el contenido en otra carpeta.</li></ol><p>Aunque sea simple, ya aparecen conceptos clave: FlowFiles, processors, relationships, connections y colas.</p><h2 id="buenas-practicas-iniciales" tabindex="-1">Buenas practicas iniciales <a class="header-anchor" href="#buenas-practicas-iniciales" aria-label="Permalink to &quot;Buenas practicas iniciales&quot;">​</a></h2><ul><li>Nombra los processors por intencion, no solo por tipo.</li><li>Divide el flujo en process groups pequenos.</li><li>Conecta o termina todas las relationships.</li><li>Configura back pressure desde el principio.</li><li>Separa rutas de exito, fallo y retry.</li><li>Usa parameter contexts para valores por entorno.</li><li>Versiona flujos con NiFi Registry.</li><li>Documenta que entra, que sale y quien es propietario.</li></ul><h2 id="relacion-con-pipelines" tabindex="-1">Relacion con pipelines <a class="header-anchor" href="#relacion-con-pipelines" aria-label="Permalink to &quot;Relacion con pipelines&quot;">​</a></h2><p>NiFi suele ser una pieza dentro de un pipeline de datos. Puede encargarse de ingesta, routing y entrega, mientras que otras herramientas hacen orquestacion, transformacion pesada o modelado analitico.</p><p>Recursos relacionados:</p><ul><li><a href="./../pipelines/01-introduccion">Pipelines de datos</a></li><li><a href="./../kafka/01-introduccion-y-arquitectura">Apache Kafka</a></li><li><a href="./../spark/01-introduccion-a-apache-spark">Apache Spark</a></li><li><a href="./../airflow/01-introduccion-y-arquitectura">Apache Airflow</a></li></ul>',47)])])}const h=a(l,[["render",s]]);export{m as __pageData,h as default};
